  rankMaestro: { es:"Maestro",en:"Master",pt:"Mestre",fr:"Maître",de:"Meister",it:"Maestro",tr:"Usta",ru:"Мастер",pl:"Mistrz",nl:"Meester",sv:"Mästare",da:"Mester",fi:"Mestari",no:"Mester",zh:"大师",ja:"マスター",ko:"마스터",hi:"मास्टर",th:"มาสเตอร์",vi:"Thạc sĩ",id:"Maestro",ar:"ماستر" },
  "rankGran Maestro": { es:"Gran Maestro",en:"Grand Master",pt:"Grão-Mestre",fr:"Grand Maître",de:"Großmeister",it:"Gran Maestro",tr:"Büyük Usta",ru:"Гран-Мастер",pl:"Wielki Mistrz",nl:"Grootmeester",sv:"Stormästare",da:"Stormester",fi:"Suurmestari",no:"Stormester",zh:"宗师",ja:"グランドマスター",ko:"그랜드마스터",hi:"ग्रैंड मास्टर",th:"แกรนด์มาสเตอร์",vi:"Đại sư",id:"Grand Master",ar:"غراند ماستر" },
